// GDA UNIFIED SCORE + AUTO COMPETITIVE INTEL (S-095)
const items = $input.all();
const EIS_NAICS = ['541330','541511','541512','541513','541519','541611','541690','541715','541990','611430','561210','561110'];
const TARGET_AGENCIES = ['socom','tradoc','peo stri','inscom','cybercom','disa','indopacom','mda','missile defense','faa'];

function calculateGDAScore(opp) {
  let score = 0;
  const title = ((opp.title || opp.name || opp.opp_title || '') + ' ' + (opp.description || '')).toLowerCase();
  const naics = opp.naics_code || opp.naics || '';
  const setAside = (opp.set_aside || opp.set_aside_type || '').toLowerCase();
  const agency = (opp.agency || opp.federal_agency || opp.department || '').toLowerCase();
  const value = parseFloat(opp.value || opp.estimated_value || 0);
  const daysLeft = opp.due_date ? Math.ceil((new Date(opp.due_date) - new Date()) / 86400000) : 90;

  // TIER 1: MISSION FIT (40)
  let naicsPts = EIS_NAICS.includes(naics) ? 15 : naics?.startsWith('5415') ? 8 : naics?.startsWith('541') ? 5 : 0;
  score += naicsPts;
  let mp = 0;
  if (/seta|systems engineering/.test(title)) mp = Math.max(mp, 15);
  if (/simulat|training|virtual/.test(title)) mp = Math.max(mp, 12);
  if (/missile|defense|shield|golden dome/.test(title)) mp = Math.max(mp, 12);
  if (/cyber|information security|c5isr/.test(title)) mp = Math.max(mp, 10);
  if (/intel|intelligence|sigint|geoint/.test(title)) mp = Math.max(mp, 10);
  if (/air traffic|atc|faa|bnatcs/.test(title)) mp = Math.max(mp, 8);
  if (/it support|help desk|network|cloud/.test(title)) mp = Math.max(mp, 8);
  score += Math.min(mp, 15);
  let ouPts = 2;
  if (/seta|training|simulat|peo stri|tradoc/.test(title)) ouPts = 10;
  else if (/cyber|protect|security|disa/.test(title)) ouPts = 10;
  else if (/software|engineer|develop|integrat/.test(title)) ouPts = 10;
  else if (/socom|inscom|army|navy/.test(title)) ouPts = 7;
  else if (/support|manage|consult/.test(title)) ouPts = 5;
  score += ouPts;

  // TIER 2: WINNABILITY (35)
  let saPts = 3;
  if (/sdvosb|service.disabled/.test(setAside)) saPts = 10;
  else if (/8\(a\)|8a/.test(setAside)) saPts = 10;
  else if (/hubzone/.test(setAside)) saPts = 9;
  else if (/small business/.test(setAside) && !/no set/.test(setAside)) saPts = 8;
  score += saPts;
  let ppPts = 2;
  for (const ta of TARGET_AGENCIES) { if (agency.includes(ta)) { ppPts = 15; break; } }
  if (ppPts < 15 && /army|war/.test(agency)) ppPts = 10;
  if (ppPts < 10 && /navy|air force|defense|dod/.test(agency)) ppPts = 7;
  score += ppPts;
  let compPts = /sole.source|j&a|limited/.test(setAside + ' ' + title) ? 10 : /small business/.test(setAside) ? 7 : 3;
  score += compPts;

  // TIER 3: STRATEGIC VALUE (25)
  let valPts = value >= 500000 && value <= 10000000 ? 10 : value > 10000000 && value <= 50000000 ? 8 : value > 50000000 ? 5 : value > 100000 ? 4 : 3;
  score += valPts;
  let rwPts = 2;
  if (/iews|recompete/.test(title)) rwPts = 10;
  if (/shield|mda/.test(title + ' ' + agency)) rwPts = Math.max(rwPts, 8);
  if (/idiq|task order|delivery order/.test(title)) rwPts = Math.max(rwPts, 6);
  score += rwPts;
  score += daysLeft > 45 ? 5 : daysLeft > 30 ? 4 : daysLeft > 14 ? 2 : 1;

  return Math.min(Math.max(Math.round(score), 0), 100);
}

// Build competitive intel summary for high-scoring opps
function buildCompetitiveContext(opp, gdaScore) {
  if (gdaScore < 60) return { competitors: 'Score too low for auto-enrichment', incumbent: 'N/A', vehicles: 'N/A' };
  const agency = (opp.agency || opp.federal_agency || opp.department || '').toLowerCase();
  const naics = opp.naics_code || opp.naics || '';
  const setAside = (opp.set_aside || opp.set_aside_type || '').toLowerCase();
  const title = (opp.title || opp.name || '').toLowerCase();

  // Agency-specific incumbent knowledge (from GovTribe analysis)
  const incumbentMap = {
    'socom': 'CACI NSS ($1.2B/859 awards), Amentum/Jacobs ($1.8B), iGov ($771M), Blue TECH ($382M)',
    'mda': 'Lockheed Martin ($10B+), Northrop Grumman ($5.3B), JHU APL ($985M/76 awards), Boeing ($951M)',
    'missile defense': 'Lockheed Martin ($10B+), Northrop Grumman ($5.3B), JHU APL ($985M)',
    'tradoc': 'CACI, Leidos, Booz Allen Hamilton - SETA/training dominant',
    'peo stri': 'Cole Engineering, Leidos, CACI - simulation/training SETA',
    'inscom': 'Leidos, SAIC, Booz Allen - intel/SIGINT dominant',
    'cybercom': 'Leidos, ManTech, Booz Allen - cyber operations',
    'disa': 'Leidos, SAIC, General Dynamics IT - enterprise IT',
    'faa': 'Leidos, SAIC, Raytheon - ATC modernization'
  };

  let incumbent = 'Unknown - needs GovTribe enrichment';
  for (const [key, val] of Object.entries(incumbentMap)) {
    if (agency.includes(key)) { incumbent = val; break; }
  }

  // Vehicle eligibility
  const vehicles = [];
  if (/shield/.test(title + ' ' + agency)) vehicles.push('MDA SHIELD (EIS ON)');
  if (/small business|sdvosb|8\(a\)/.test(setAside)) vehicles.push('8(a) STARS III', 'VETS 2');
  if (naics.startsWith('5415')) vehicles.push('CIO-SP4', 'ITES-4S', 'Alliant 3');
  if (/training|simulat/.test(title)) vehicles.push('JETS 2', 'SeaPort-NxG');
  if (vehicles.length === 0) vehicles.push('GSA MAS', 'CIO-SP4');

  // SB competitors in EIS space
  const sbCompetitors = /sdvosb|service.disabled/.test(setAside)
    ? 'iGov, Blue TECH, Arma Global, Spathe Systems, FITT'
    : /small business/.test(setAside)
    ? 'iGov, Blue TECH, Novetta, Altamira, DLT Solutions'
    : 'Full & open - primes: Leidos, SAIC, CACI, BAH, L3Harris';

  return {
    incumbent,
    competitors: sbCompetitors,
    vehicles: vehicles.join(', '),
    enrichment_date: new Date().toISOString(),
    auto_enriched: true
  };
}

const opps = items[0]?.json?.body?.opportunities || items[0]?.json?.opportunities || [];
if (!opps.length) return [{ json: { _hasData: false, message: 'No opportunities to score' } }];

const scored = opps.map(o => {
  const gda_score = calculateGDAScore(o);
  const label = gda_score >= 80 ? 'PURSUE' : gda_score >= 60 ? 'EVALUATE' : gda_score >= 40 ? 'MONITOR' : 'PASS';
  const compIntel = buildCompetitiveContext(o, gda_score);
  return { json: { 
    ...o, 
    gda_score, 
    gda_label: label, 
    eis_fit_score: gda_score, 
    fit_score: gda_score,
    incumbent_analysis: compIntel.incumbent,
    likely_competitors: compIntel.competitors,
    eligible_vehicles: compIntel.vehicles,
    enrichment_date: compIntel.enrichment_date,
    auto_enriched: compIntel.auto_enriched || false
  }};
});
return scored;

